const fs = require('fs');

// Read the test file
const filePath = '/workspaces/gmail-automation/packages/classification-engine/tests/unit/audit-trail.test.ts';
let content = fs.readFileSync(filePath, 'utf8');

// Function to convert finalDecision to aiLabelFiltering + actionDetermination
function convertFinalDecision(finalDecisionBlock) {
  // Extract assignedLabels
  const primaryMatch = finalDecisionBlock.match(/primary:\s*'([^']+)'/);
  const secondaryMatch = finalDecisionBlock.match(/secondary:\s*\[([^\]]*)\]/);

  const primary = primaryMatch ? primaryMatch[1] : 'unknown';
  const secondaryStr = secondaryMatch ? secondaryMatch[1] : '';
  const secondary = secondaryStr ? secondaryStr.split(',').map(s => s.trim().replace(/'/g, '')) : [];

  // Extract actions
  const actionsMatch = finalDecisionBlock.match(/determinedActions:\s*\[([^\]]*)\]/);
  const actionsStr = actionsMatch ? actionsMatch[1] : '';
  const actions = actionsStr ? actionsStr.split(',').map(s => s.trim()) : [];

  // Extract reasoning
  const reasoningMatch = finalDecisionBlock.match(/actionReasoning:\s*'([^']*)'/);
  const reasoning = reasoningMatch ? reasoningMatch[1] : '';

  // Extract processing time
  const timeMatch = finalDecisionBlock.match(/processingDurationMs:\s*(\d+)/);
  const time = timeMatch ? timeMatch[1] : '10';

  return {
    aiLabelFiltering: `aiLabelFiltering: {
          assignedLabels: {
            primary: '${primary}',
            secondary: [${secondary.map(s => `'${s}'`).join(', ')}],
          },
          processingDurationMs: ${time},
          validationErrors: [],
          explainabilityTrace: {
            aiClassificationInput: {
              primaryCategory: '${primary}',
              secondaryCategories: [${secondary.map(s => `'${s}'`).join(', ')}],
              confidence: 0,
              reasoning: '',
              categoryScores: {},
            },
            labelAssignmentRationale: '',
            filteredLabels: [],
          },
        }`,
    actionDetermination: `actionDetermination: {
          determinedActions: [${actions.join(', ')}],
          actionReasoning: '${reasoning}',
          processingDurationMs: 5,
        }`
  };
}

// Replace all finalDecision blocks
content = content.replace(/finalDecision:\s*\{[\s\S]*?explainabilityTrace:\s*\{[\s\S]*?\},\s*\}/g, (match) => {
  const converted = convertFinalDecision(match);
  return `${converted.aiLabelFiltering},\n        ${converted.actionDetermination}`;
});

// Also replace timing references
content = content.replace(/stageTimings\.finalDecision/g, 'stageTimings.aiLabelFiltering');

// Write back
fs.writeFileSync(filePath, content, 'utf8');
console.log('Fixed audit-trail.test.ts');
