/**
 * Unit Tests for Classification Pipeline Orchestrator
 *
 * These tests focus on orchestration logic: stage execution order,
 * context propagation, conditional AI flow, error handling, and result aggregation.
 * All stages are mocked to isolate pipeline orchestrator logic.
 */

// Mock all stage modules before imports
jest.mock('../../src/stages/hard-assertions', () => ({
  executeHardAssertions: jest.fn((email, session, result) => {
    result.candidateScores.financial = { score: 15, hardAssertion: true };
  }),
}));

jest.mock('../../src/stages/strong-indicators', () => ({
  executeStrongIndicators: jest.fn((email, session, result) => {
    result.candidateScores.personal = { score: 10, seedScore: 10 };
  }),
}));

jest.mock('../../src/stages/rule-scoring', () => ({
  executeRuleScoring: jest.fn((email, session, result) => {
    result.candidateScores.financial = {
      ...result.candidateScores.financial,
      score: 15.5,
      ruleScore: 0.5,
    };
  }),
}));

jest.mock('../../src/stages/attribute-detection', () => ({
  executeAttributeDetection: jest.fn(),
}));

jest.mock('../../src/stages/attribute-influence', () => ({
  executeAttributeInfluence: jest.fn((email, session, result) => {
    if (result.candidateScores.financial) {
      result.candidateScores.financial.score = 17.5;
      result.candidateScores.financial.attributeBonus = 2;
    }
  }),
}));

jest.mock('../../src/stages/disambiguation', () => ({
  executeDisambiguation: jest.fn(),
}));

jest.mock('../../src/stages/multi-label-selection', () => ({
  executeMultiLabelSelection: jest.fn((email, session, result) => {
    result.selectedLabels = [
      {
        category: 'financial',
        subtype: null,
        confidence: 0.88,
        score: 17.5,
        isPrimary: true,
        labelOrder: 1,
        selectionRationale: 'Highest scoring category',
      },
    ];
    result.primaryCategory = 'financial';
    result.confidence = 0.88;
    result.selectionSummary = {
      totalLabels: 1,
      primaryCategory: 'financial',
      confidenceRange: [0.88, 0.88],
      selectionMethod: 'singleLabel',
      needsAi: false,
    };
  }),
}));

jest.mock('../../src/stages/ai-routing', () => ({
  aiRoutingStage: jest.fn((email, session, result) => {
    // By default, skip AI (high confidence)
    result.needsAiClassification = false;
  }),
}));

jest.mock('../../src/stages/ai-feature-extraction', () => ({
  aiFeatureExtractionStage: jest.fn((email, session, result) => {
    result.aiFeatureExtraction = {
      semanticIntent: { primaryPurpose: 'information' },
      categoryEnhancements: { suggested: ['financial'] },
    };
  }),
}));

jest.mock('../../src/stages/ai-classification', () => ({
  aiClassificationStage: jest.fn(),
}));

jest.mock('../../src/stages/ai-label-filtering', () => ({
  aiLabelFilteringStage: jest.fn(),
}));

jest.mock('../../src/stages/action-determination', () => ({
  actionDeterminationStage: jest.fn((email, session, result) => {
    result.determinedActions = ['markAsRead'];
  }),
}));

import { ClassificationPipeline } from '../../src/pipeline/classification-pipeline';
import { EmailMessage } from '../../src/types/email-message';
import { CategoryConfiguration, ProcessingConfig } from '../../src/types/category-configuration';
import { hardAssertionsStage } from '../../src/stages/hard-assertions';
import { strongIndicatorsStage } from '../../src/stages/strong-indicators';
import { ruleScoringStage } from '../../src/stages/rule-scoring';
import { attributeDetectionStage } from '../../src/stages/attribute-detection';
import { attributeInfluenceStage } from '../../src/stages/attribute-influence';
import { disambiguationStage } from '../../src/stages/disambiguation';
import { multiLabelSelectionStage } from '../../src/stages/multi-label-selection';
import { aiRoutingStage } from '../../src/stages/ai-routing';
import { aiFeatureExtractionStage } from '../../src/stages/ai-feature-extraction';
import { aiClassificationStage } from '../../src/stages/ai-classification';
import { aiLabelFilteringStage } from '../../src/stages/ai-label-filtering';
import { actionDeterminationStage } from '../../src/stages/action-determination';

describe('ClassificationPipeline', () => {
  // Mock email for testing
  const mockEmail: EmailMessage = {
    id: 'test-msg-001',
    threadId: 'thread-001',
    gmailLabels: ['INBOX'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test Email' },
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Date', value: new Date().toISOString() },
      ],
      body: {
        data: Buffer.from('Test email body content').toString('base64url'),
      },
    },
    subject: 'Test Email',
    from: { email: 'sender@example.com', name: 'Sender', raw: 'Sender <sender@example.com>' },
    to: [{ email: 'recipient@example.com', name: 'Recipient', raw: 'Recipient <recipient@example.com>' }],
    date: new Date(),
    bodyPlain: 'Test email body content',
    isProcessed: false,
    processingPriority: 1,
  };

  // Minimal config for unit tests
  const minimalProcessingConfig: ProcessingConfig = {
    version: 1,
    taxonomyNotes: 'Unit test configuration',
    settings: {
      initialization: {
        applyHardAssertions: true,
        seedCategoryScores: true,
      },
      ruleScoring: {
        useLexicalPatterns: true,
        applySubtypeRules: true,
        boundedAggregation: true,
      },
      attributeProcessing: {
        detectSelfSent: true,
        resolveDomains: true,
        deriveContextFlags: true,
      },
      attributeInfluence: {
        applyBonuses: true,
        applyPenalties: true,
        enforceCaps: true,
      },
      disambiguation: {
        pairwiseAdjustments: true,
        confidenceGapThreshold: 0.15,
      },
      multiLabelSelection: {
        maxLabels: 2,
        minSecondaryConfidence: 0.6,
        allowedCombinations: [],
      },
      aiRouting: {
        highConfidenceThreshold: 15,
        aiRequiredThreshold: 12,
        skipAiConditions: [],
      },
    },
    confidenceThresholds: {
      highConfidence: 0.8,
      mediumConfidence: 0.5,
      lowConfidence: 0.3,
      aiClassificationRequired: 0.6,
      manualReviewRequired: 0.2,
      secondaryLabelMinGap: 0.15,
    },
    categorySignals: {},
    multiLabelPolicy: {
      maxTopLevelLabels: 2,
      minConfidenceForAdditional: 0.6,
      minDeltaPrimarySecondary: 0.15,
      allowFinancialActionableCopresence: false,
    },
    domainSignalOverrides: {},
    domainSignalResolution: {
      mode: 'runtimeResolved',
      source: 'config/domain-sources.json',
      notes: 'Test configuration',
    },
    topLevelCategories: {},
    attributes: {
      schema: {},
      detectors: [],
      derived: {},
      attributeBonusMap: {},
    },
    attributeRelevance: {
      RolesLegend: {
        CORE: 'Core',
        PRIMARY_BOOST: 'Primary boost',
        SECONDARY_BOOST: 'Secondary boost',
        DISAMBIGUATOR: 'Disambiguator',
        FILTER: 'Filter',
        STRUCTURAL: 'Structural',
        DERIVED_LINK: 'Derived link',
        NEUTRAL: 'Neutral',
      },
    },
    aiPrompts: {
      featureExtraction: {
        systemPrompt: [],
        userPrompt: [],
      },
      finalClassification: {
        systemPrompt: [],
        userPrompt: [],
      },
    },
    featureExtractionSchema: {
      type: 'object',
      properties: {},
      required: [],
      additionalProperties: false,
    },
  };

  const minimalConfig: CategoryConfiguration = {
    version: '1.0.0',
    lastModified: new Date(),
    hash: 'test-config-hash',
    processingConfig: minimalProcessingConfig,
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  beforeEach(() => {
    // Clear all mock calls before each test
    jest.clearAllMocks();
  });

  describe('Constructor', () => {
    it('should initialize with valid configuration', () => {
      expect(() => new ClassificationPipeline(minimalConfig)).not.toThrow();
    });

    it('should throw error with invalid configuration', () => {
      const invalidConfig = {
        ...minimalConfig,
        processingConfig: { ...minimalProcessingConfig, confidenceThresholds: undefined },
      };
      expect(() => new ClassificationPipeline(invalidConfig as unknown as CategoryConfiguration)).toThrow();
    });

    it('should validate confidence thresholds on initialization', () => {
      const invalidThresholds: CategoryConfiguration = {
        ...minimalConfig,
        processingConfig: {
          ...minimalProcessingConfig,
          confidenceThresholds: {
            highConfidence: -0.1, // Invalid negative value
            mediumConfidence: 0.5,
            lowConfidence: 0.3,
            aiClassificationRequired: 0.6,
            manualReviewRequired: 0.2,
            secondaryLabelMinGap: 0.15,
          },
        },
      };
      expect(() => new ClassificationPipeline(invalidThresholds)).toThrow(/confidence/i);
    });
  });

  describe('Stage Execution Order', () => {
    it('should execute all 10 stages in correct order when AI is skipped', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      // Verify all rule-based stages called
      expect(hardAssertionsStage).toHaveBeenCalled();
      expect(strongIndicatorsStage).toHaveBeenCalled();
      expect(ruleScoringStage).toHaveBeenCalled();
      expect(attributeDetectionStage).toHaveBeenCalled();
      expect(attributeInfluenceStage).toHaveBeenCalled();
      expect(disambiguationStage).toHaveBeenCalled();
      expect(multiLabelSelectionStage).toHaveBeenCalled();
      expect(aiRoutingStage).toHaveBeenCalled();

      // AI stages should not be called (needsAiClassification = false by mock)
      expect(aiFeatureExtractionStage).not.toHaveBeenCalled();
      expect(aiClassificationStage).not.toHaveBeenCalled();
      expect(aiLabelFilteringStage).not.toHaveBeenCalled();

      // Action determination always runs
      expect(actionDeterminationStage).toHaveBeenCalled();
    });

    it('should execute AI stages when needsAiClassification is true', async () => {
      // Mock aiRoutingStage to enable AI
      (aiRoutingStage as jest.Mock).mockImplementationOnce((email, session, result) => {
        result.needsAiClassification = true;
      });

      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      // All stages should be called including AI stages
      expect(aiRoutingStage).toHaveBeenCalled();
      expect(aiFeatureExtractionStage).toHaveBeenCalled();
      expect(aiClassificationStage).toHaveBeenCalled();
      expect(aiLabelFilteringStage).toHaveBeenCalled();
      expect(actionDeterminationStage).toHaveBeenCalled();
    });

    it('should execute stages 1-7 before AI routing (stage 8a)', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const callOrder: string[] = [];

      (hardAssertionsStage as jest.Mock).mockImplementation(() => callOrder.push('hard-assertions'));
      (strongIndicatorsStage as jest.Mock).mockImplementation(() => callOrder.push('strong-indicators'));
      (ruleScoringStage as jest.Mock).mockImplementation(() => callOrder.push('rule-scoring'));
      (attributeDetectionStage as jest.Mock).mockImplementation(() => callOrder.push('attribute-detection'));
      (attributeInfluenceStage as jest.Mock).mockImplementation(() => callOrder.push('attribute-influence'));
      (disambiguationStage as jest.Mock).mockImplementation(() => callOrder.push('disambiguation'));
      (multiLabelSelectionStage as jest.Mock).mockImplementation(() => callOrder.push('multi-label'));
      (aiRoutingStage as jest.Mock).mockImplementation(() => callOrder.push('ai-routing'));

      await pipeline.classify(mockEmail);

      expect(callOrder).toEqual([
        'hard-assertions',
        'strong-indicators',
        'rule-scoring',
        'attribute-detection',
        'attribute-influence',
        'disambiguation',
        'multi-label',
        'ai-routing',
      ]);
    });
  });

  describe('Context Propagation', () => {
    it('should pass the same result object to all stages', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      // Get result object from first stage call
      const resultFromStage1 = (hardAssertionsStage as jest.Mock).mock.calls[0][2];
      const resultFromStage2 = (strongIndicatorsStage as jest.Mock).mock.calls[0][2];
      const resultFromStage3 = (ruleScoringStage as jest.Mock).mock.calls[0][2];

      // All stages should receive the same object instance
      expect(resultFromStage1).toBe(resultFromStage2);
      expect(resultFromStage2).toBe(resultFromStage3);
    });

    it('should pass email and session to all stages', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      // Verify stages received correct parameters
      expect(hardAssertionsStage).toHaveBeenCalledWith(
        expect.objectContaining({ id: 'test-msg-001' }),
        expect.objectContaining({ id: expect.any(String) }),
        expect.any(Object),
        expect.any(Object)
      );
    });

    it('should initialize result with empty structures', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      const result = (hardAssertionsStage as jest.Mock).mock.calls[0][2];

      // Result should be initialized with empty structures
      expect(result.candidateScores).toBeDefined();
      expect(result.selectedLabels).toBeDefined();
      expect(result.explainabilityTrace).toBeDefined();
    });

    it('should accumulate stage mutations to result object', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const finalResult = await pipeline.classify(mockEmail);

      // Result should have mutations from all stages
      expect(finalResult.candidateScores.financial).toBeDefined();
      expect(finalResult.candidateScores.financial.score).toBe(17.5); // After attribute influence
      expect(finalResult.selectedLabels).toHaveLength(1);
      expect(finalResult.primaryCategory).toBe('financial');
    });
  });

  describe('Batch Processing', () => {
    it('should process multiple emails sequentially', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const emails = [
        { ...mockEmail, id: 'msg-001' },
        { ...mockEmail, id: 'msg-002' },
        { ...mockEmail, id: 'msg-003' },
      ];

      const results = await pipeline.classifyBatch(emails);

      expect(results).toHaveLength(3);
      expect(hardAssertionsStage).toHaveBeenCalledTimes(3);
      expect(results[0].selectedLabels).toBeDefined();
      expect(results[1].selectedLabels).toBeDefined();
      expect(results[2].selectedLabels).toBeDefined();
    });

    it('should handle empty batch gracefully', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const results = await pipeline.classifyBatch([]);

      expect(results).toEqual([]);
      expect(hardAssertionsStage).not.toHaveBeenCalled();
    });

    it('should process each email with fresh result object', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const emails = [
        { ...mockEmail, id: 'msg-001' },
        { ...mockEmail, id: 'msg-002' },
      ];

      await pipeline.classifyBatch(emails);

      const result1 = (hardAssertionsStage as jest.Mock).mock.calls[0][2];
      const result2 = (hardAssertionsStage as jest.Mock).mock.calls[1][2];

      // Each email should get a separate result object
      expect(result1).not.toBe(result2);
    });
  });

  describe('Result Aggregation', () => {
    it('should return result with all required fields', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const result = await pipeline.classify(mockEmail);

      expect(result).toHaveProperty('selectedLabels');
      expect(result).toHaveProperty('candidateScores');
      expect(result).toHaveProperty('selectionSummary');
      expect(result).toHaveProperty('processingDurationMs');
      expect(result).toHaveProperty('primaryCategory');
      expect(result).toHaveProperty('confidence');
    });

    it('should track performance timing', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const startTime = Date.now();
      const result = await pipeline.classify(mockEmail);
      const endTime = Date.now();

      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
      expect(result.processingDurationMs).toBeLessThanOrEqual(endTime - startTime + 10); // 10ms tolerance
    });

    it('should include action determination results', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      const result = await pipeline.classify(mockEmail);

      expect(result.determinedActions).toEqual(['markAsRead']);
    });
  });

  describe('Error Handling', () => {
    it('should propagate stage errors with pipeline context', async () => {
      (hardAssertionsStage as jest.Mock).mockImplementationOnce(() => {
        throw new Error('Stage failed');
      });

      const pipeline = new ClassificationPipeline(minimalConfig);
      await expect(pipeline.classify(mockEmail)).rejects.toThrow(/Classification pipeline failed/);
    });

    it('should include email ID in error message', async () => {
      (strongIndicatorsStage as jest.Mock).mockImplementationOnce(() => {
        throw new Error('Test error');
      });

      const pipeline = new ClassificationPipeline(minimalConfig);
      await expect(pipeline.classify(mockEmail)).rejects.toThrow(/test-msg-001/);
    });

    it('should include stage name in error message', async () => {
      (ruleScoringStage as jest.Mock).mockImplementationOnce(() => {
        throw new Error('Scoring failed');
      });

      const pipeline = new ClassificationPipeline(minimalConfig);
      await expect(pipeline.classify(mockEmail)).rejects.toThrow(/rule-scoring/i);
    });
  });

  describe('Conditional AI Flow', () => {
    it('should skip AI stages when high confidence', async () => {
      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      expect(aiFeatureExtractionStage).not.toHaveBeenCalled();
      expect(aiClassificationStage).not.toHaveBeenCalled();
      expect(aiLabelFilteringStage).not.toHaveBeenCalled();
    });

    it('should execute AI stages when low confidence', async () => {
      (aiRoutingStage as jest.Mock).mockImplementationOnce((email, session, result) => {
        result.needsAiClassification = true;
      });

      const pipeline = new ClassificationPipeline(minimalConfig);
      await pipeline.classify(mockEmail);

      expect(aiFeatureExtractionStage).toHaveBeenCalled();
      expect(aiClassificationStage).toHaveBeenCalled();
      expect(aiLabelFilteringStage).toHaveBeenCalled();
    });

    it('should always run action determination regardless of AI routing', async () => {
      // Test with AI skipped
      const pipeline1 = new ClassificationPipeline(minimalConfig);
      await pipeline1.classify(mockEmail);
      expect(actionDeterminationStage).toHaveBeenCalledTimes(1);

      jest.clearAllMocks();

      // Test with AI enabled
      (aiRoutingStage as jest.Mock).mockImplementationOnce((email, session, result) => {
        result.needsAiClassification = true;
      });

      const pipeline2 = new ClassificationPipeline(minimalConfig);
      await pipeline2.classify(mockEmail);
      expect(actionDeterminationStage).toHaveBeenCalledTimes(1);
    });
  });
});

