      expect(aiFeatureExtractionStage).toHaveBeenCalled();
      expect(aiClassificationStage).toHaveBeenCalled();
      expect(aiLabelFilteringStage).toHaveBeenCalled();
    });

    it('should always run action determination regardless of AI routing', async () => {
      // Test with AI skipped
      const pipeline1 = new ClassificationPipeline(minimalConfig);
